function navigate(path: string): void { window.history.pushState({}, '', path); window.dispatchEvent(new PopStateEvent('popstate')); window.scrollTo({ top: 0, behavior: 'smooth' }); }
function usePath(): string { const [path, setPath] = useState(window.location.pathname + window.location.search); useEffect(() => { const handler = (): void => setPath(window.location.pathname + window.location.search); window.addEventListener('popstate', handler); return () => window.removeEventListener('popstate', handler); }, []); return path; }
function LinkButton({ to, children, className }: { to: string; children: React.ReactNode; className?: string }): React.ReactElement { return <a href={to} className={className} onClick={(event) => { event.preventDefault(); navigate(to); }}>{children}</a>; }
function Brand(): React.ReactElement { return <LinkButton to="/" className="brand brand-wordmark"><img src="/commandforge-header-wordmark.svg" alt="CommandForgeAI" /></LinkButton>; }
function courseBySlug(slug?: string): Course { return courses.find((course) => course.slug === slug) ?? courses[0]; }

